// Generates a REAL repetition-ended transcript from the shared TS engine and
// writes it as a Foundry fixture, so the on-chain ReplayVerifier can be proven
// to end the identical move sequence at the identical point (cross-language
// parity for the anti-stall rule, which lives above applyMove).
//
//   node contracts/test/fixtures/gen-repetition.mjs
//
// Deterministic: a seeded LCG drives random legal play until adjudicate() ends
// a game by threefold repetition (swept board, noCaptureCount < 40 — i.e. the
// repeat, not the 40-ply backstop). Mirrors packages/engine/test/repetition.test.ts.
import { writeFileSync } from "node:fs";
import { fileURLToPath } from "node:url";
import { dirname, join } from "node:path";
import { initialState, applyMove, legalMovesMask, adjudicate } from "../../../packages/engine/src/awale.ts";

function lcg(seed) {
  let x = seed >>> 0;
  return () => ((x = (Math.imul(x, 1664525) + 1013904223) >>> 0) / 2 ** 32);
}

let picked = null;
for (let seed = 1; seed <= 5000 && !picked; seed++) {
  const rnd = lcg(seed);
  const moves = [];
  let s = initialState();
  for (let i = 0; i < 400; i++) {
    const mask = legalMovesMask(s);
    const pool = [];
    for (let h = 0; h < 6; h++) if (mask & (1 << h)) pool.push(h);
    if (!pool.length) break;
    const mv = pool[Math.floor(rnd() * pool.length)];
    moves.push(mv);
    s = applyMove(s, mv);
    const adj = adjudicate(moves);
    if (adj.over) {
      // swept board AND under the 40-ply backstop ⇒ the ending was repetition
      if (adj.pits.every((p) => p === 0) && adj.noCaptureCount < 40) {
        picked = { seed, moves, winner: adj.winner, store0: adj.store0, store1: adj.store1 };
      }
      break;
    }
  }
}

if (!picked) throw new Error("no repetition game found in 5000 seeds");

// sanity: truncating the last move must NOT be over — the repeat is what ended it
const oneShort = adjudicate(picked.moves.slice(0, -1));
if (oneShort.over) throw new Error("not minimal: ended before the final move");

const out = {
  _comment: "Auto-generated by gen-repetition.mjs — a threefold-repetition game from the TS engine. startTurn 0.",
  seed: picked.seed,
  startTurn: 0,
  moves: picked.moves,
  winner: picked.winner,
  store0: picked.store0,
  store1: picked.store1,
};
const here = dirname(fileURLToPath(import.meta.url));
writeFileSync(join(here, "repetition.json"), JSON.stringify(out, null, 2) + "\n");
console.log(`seed ${picked.seed}: ${picked.moves.length} plies, winner ${picked.winner}, stores ${picked.store0}/${picked.store1}`);
